const e=[{slug:"linear-algebra",title:"Linear Algebra",blurb:"Vectors, matrices, and the transformations that move data through every layer of a network.",topics:[{slug:"vectors",title:"Vectors & Vector Spaces",summary:"A vector is a list of numbers and a point in space at once. Addition, scaling, and span set the stage for everything that follows.",lessonPath:"/ml/foundations/vectors"},{slug:"dot-product",title:"Dot Product & Cosine Similarity",summary:"One number that measures alignment. The dot product powers similarity search, projections, and the core of attention.",lessonPath:"/ml/foundations/dot-product"},{slug:"matrix-multiply",title:"Matrix Multiplication",summary:"Rows meet columns to compose linear maps. Every dense layer is a matrix multiply; reading shapes correctly avoids most bugs.",lessonPath:"/ml/foundations/matrices"},{slug:"eigen",title:"Eigenvectors & Eigenvalues",summary:"Directions a transform only stretches, never rotates. Eigenvalues quantify the stretch and explain stability, PageRank, and PCA.",lessonPath:"/ml/foundations/eigenvectors"},{slug:"svd",title:"Singular Value Decomposition",summary:"Factor any matrix into rotate, scale, rotate. SVD underlies low-rank compression, pseudo-inverses, and PCA on non-square data.",lessonPath:"/ml/foundations/pca"},{slug:"projections",title:"Projections & Orthogonality",summary:"Drop a vector onto a subspace to find its closest shadow. Projection is least squares, and orthogonality keeps coordinates independent.",lessonPath:"/ml/foundations/projections"},{slug:"norms",title:"Norms & Distance",summary:'L1, L2, and infinity norms each measure size differently. The norm you pick shapes regularization, gradients, and what "close" means.',lessonPath:"/ml/foundations/norms"}]},{slug:"calculus",title:"Calculus & Gradients",blurb:"Derivatives, the chain rule, and the gradient machinery that lets a model learn from its mistakes.",topics:[{slug:"derivatives",title:"Derivatives & Slopes",summary:"The instantaneous rate of change at a point. A derivative tells you which way to nudge a parameter to lower the loss.",lessonPath:"/ml/foundations/derivatives"},{slug:"chain-rule",title:"The Chain Rule",summary:"Differentiate a composition by multiplying local rates. This single rule is the entire reason backpropagation works.",lessonPath:"/ml/foundations/chain-rule"},{slug:"gradients",title:"Gradients & Directional Derivatives",summary:"The gradient is the vector of partials pointing toward steepest ascent. Step against it to minimize a multivariable loss.",lessonPath:"/ml/optimization/gradient-descent"},{slug:"jacobian-hessian",title:"Jacobian & Hessian",summary:"The Jacobian stacks first derivatives of a vector function; the Hessian holds second derivatives and reveals curvature.",lessonPath:"/ml/foundations/jacobian-hessian"},{slug:"gradient-descent-geometry",title:"Gradient Descent Geometry",summary:"Watch a step roll downhill on a loss surface. Step size, valleys, and saddle points all show up as shapes of the terrain.",lessonPath:"/ml/optimization/gradient-descent"},{slug:"backprop",title:"Backpropagation",summary:"Reverse-mode autodiff: one forward pass caches activations, one backward pass distributes gradient to every weight.",lessonPath:"/ml/foundations/backprop"}]},{slug:"probability",title:"Probability & Statistics",blurb:"Distributions, Bayes, and estimation — the language for reasoning about data and uncertainty.",topics:[{slug:"distributions",title:"Distributions",summary:"Bernoulli, Gaussian, categorical, and friends. A distribution assigns probability mass or density across possible outcomes.",lessonPath:"/ml/foundations/gaussian"},{slug:"bayes",title:"Bayes' Theorem",summary:'Update a prior into a posterior as evidence arrives. Bayes turns "how likely is the data" into "how likely is the cause".',lessonPath:"/ml/foundations/bayes"},{slug:"expectation-variance",title:"Expectation & Variance",summary:"The mean is where a distribution balances; variance is how far it spreads. Both drive loss functions and convergence analysis.",lessonPath:"/ml/foundations/expectation-variance"},{slug:"mle",title:"Maximum Likelihood Estimation",summary:"Pick the parameters that make the observed data most probable. MLE is why minimizing cross-entropy fits a classifier.",lessonPath:"/ml/foundations/mle"},{slug:"covariance",title:"Covariance & Correlation",summary:"How two variables move together. The covariance matrix is the object PCA diagonalizes and whitening normalizes.",lessonPath:"/ml/foundations/covariance"},{slug:"sampling",title:"Sampling & Monte Carlo",summary:"Estimate hard integrals by drawing random samples. Sampling powers dropout, minibatching, and generative model evaluation.",lessonPath:"/ml/foundations/sampling"}]},{slug:"optimization",title:"Optimization",blurb:"How a loss actually gets minimized — convexity, the descent family, and the tricks that make training converge.",topics:[{slug:"convexity",title:"Convexity",summary:"A bowl-shaped loss has one global minimum and no traps. Convexity is the boundary between easy and hard optimization.",vizSlug:"convex-hull"},{slug:"gd-sgd",title:"Gradient Descent & SGD",summary:"Full-batch descent is exact but slow; stochastic descent trades noise for speed and often generalizes better.",lessonPath:"/ml/optimization/gradient-descent"},{slug:"momentum",title:"Momentum",summary:"Accumulate a velocity across steps to power through flat regions and damp oscillation across narrow valleys.",lessonPath:"/ml/optimization/optimizer-zoo"},{slug:"adam",title:"Adam & Adaptive Methods",summary:"Per-parameter learning rates from running estimates of gradient mean and variance. The default optimizer for most deep nets.",lessonPath:"/ml/optimization/optimizer-zoo"},{slug:"lr-schedules",title:"Learning-Rate Schedules",summary:"Warmup, decay, and cosine annealing shape the step size over training. The schedule often matters as much as the optimizer.",lessonPath:"/ml/foundations/lr-schedules"},{slug:"lagrange",title:"Lagrange Multipliers & Constraints",summary:"Optimize subject to constraints by balancing the objective gradient against constraint gradients. The basis of SVMs and KKT.",lessonPath:"/ml/foundations/lagrange"}]},{slug:"information-theory",title:"Information Theory",blurb:"Entropy, divergence, and the bits-and-surprise view that underpins most classification and generative losses.",topics:[{slug:"entropy",title:"Entropy",summary:"The average surprise of a distribution, measured in bits. Entropy is the floor on how few bits any code can use.",lessonPath:"/ml/foundations/entropy"},{slug:"cross-entropy",title:"Cross-Entropy",summary:"The cost of coding samples from one distribution using a code built for another. It is the canonical classification loss.",lessonPath:"/ml/foundations/cross-entropy"},{slug:"kl-divergence",title:"KL Divergence",summary:"Extra bits wasted by assuming the wrong distribution. KL is asymmetric, non-negative, and central to VAEs and distillation.",lessonPath:"/ml/foundations/kl-divergence"},{slug:"mutual-information",title:"Mutual Information",summary:"How much knowing one variable reduces uncertainty about another. The objective behind contrastive and self-supervised learning.",lessonPath:"/ml/foundations/mutual-information"},{slug:"perplexity",title:"Perplexity",summary:"The exponential of cross-entropy — an effective branching factor. The standard yardstick for language-model quality.",lessonPath:"/ml/foundations/perplexity"}]},{slug:"numerical-methods",title:"Numerical Methods",blurb:"Floating point, conditioning, and the stability tricks that keep real training runs from drowning in NaNs.",topics:[{slug:"floating-point",title:"Floating Point",summary:"Real numbers stored in a finite mantissa and exponent. Knowing where precision lives explains overflow, underflow, and rounding.",vizSlug:"floating-point-ieee"},{slug:"conditioning",title:"Conditioning",summary:"How much output error a small input error can produce. Ill-conditioned matrices make linear solves and training fragile.",lessonPath:"/ml/foundations/conditioning"},{slug:"newtons-method",title:"Newton's Method",summary:"Use curvature to leap toward a root or minimum in fewer steps than gradient descent — when the Hessian is affordable.",vizSlug:"cordic-trig"},{slug:"numerical-stability",title:"Numerical Stability",summary:"Log-sum-exp, stable softmax, and Kahan summation keep computations accurate when magnitudes span many orders.",lessonPath:"/ml/numerical/numerical-stability"},{slug:"finite-differences",title:"Finite Differences",summary:"Approximate a derivative from nearby function values. The go-to gradient check when autodiff results look suspicious.",lessonPath:"/ml/foundations/finite-differences"}]},{slug:"matrix-calculus",title:"Matrix Calculus & Tensors",blurb:"Broadcasting, einsum, and contraction — the vectorized thinking that turns slow loops into fast tensor ops.",topics:[{slug:"broadcasting",title:"Broadcasting",summary:"Align mismatched shapes by stretching size-1 dimensions. Master the rules and most reshape bugs disappear.",lessonPath:"/ml/foundations/broadcasting"},{slug:"einsum",title:"Einstein Summation",summary:"One notation for dot products, matmuls, batched ops, and traces. Repeated indices sum; free indices stay.",lessonPath:"/ml/foundations/einsum"},{slug:"tensor-contraction",title:"Tensor Contraction",summary:"Generalized matrix multiply over chosen axes. Contraction is how attention scores and convolutions are actually computed.",lessonPath:"/ml/foundations/tensor-contraction"},{slug:"vectorization",title:"Vectorization",summary:"Replace explicit loops with array operations that run in optimized kernels. The single biggest practical speedup in ML code.",vizSlug:"gradient-accumulation"}]}];export{e as M};
